        doc.updateMetaCharsetElement(true);
        doc.outputSettings().syntax(OutputSettings.Syntax.xml);
        // PRE: existing declaration is xml with version 2.0 to trigger update path
        XmlDeclaration existing = new XmlDeclaration("xml", false).attr("version", "2.0");
        doc.prependChild(existing);
        // ensure precondition
        assertSame(existing, doc.childNodes().get(0));
        assertEquals("2.0", existing.attr("version"), "Precondition: version should be '2.0'");

        // WHEN: applying charset should update existing xml declaration
        doc.charset(cs);

        // THEN: the same XmlDeclaration updated with new encoding and version forced to '1.0'
