        assertTrue(first instanceof XmlDeclaration, "Expected first child to remain XmlDeclaration");
        XmlDeclaration xd = (XmlDeclaration) (first instanceof XmlDeclaration ? first : null);
        assertAll("Validate updated xml declaration",
            () -> assertEquals("xml", xd.name(), "Declaration name should remain 'xml'"),
            () -> assertEquals(cs.displayName(), xd.attr("encoding"), "Encoding attribute should match charset"),
            () -> assertEquals("1.0", xd.attr("version"), "Version should be reset to '1.0'")
        );
    }
